export const getUpdateReportStatusUrl = (id: number,) => {




  return `/api/admin/reports/${id}/status`
}

/**
 * @summary Update report status (admin)
 */
export const updateReportStatus = async (id: number,
    reportStatusUpdate: ReportStatusUpdate, options?: RequestInit): Promise<void> => {

  return customFetch<void>(getUpdateReportStatusUrl(id),
  {
    ...options,
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(reportStatusUpdate)
  }
);}





export const getUpdateReportStatusMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof updateReportStatus>>, TError,{id: number;data: BodyType<ReportStatusUpdate>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof updateReportStatus>>, TError,{id: number;data: BodyType<ReportStatusUpdate>}, TContext> => {

const mutationKey = ['updateReportStatus'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof updateReportStatus>>, {id: number;data: BodyType<ReportStatusUpdate>}> = (props) => {
          const {id,data} = props ?? {};

          return  updateReportStatus(id,data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type UpdateReportStatusMutationResult = NonNullable<Awaited<ReturnType<typeof updateReportStatus>>>
    export type UpdateReportStatusMutationBody = BodyType<ReportStatusUpdate>
    export type UpdateReportStatusMutationError = ErrorType<unknown>

    /**
 * @summary Update report status (admin)
 */
export const useUpdateReportStatus = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof updateReportStatus>>, TError,{id: number;data: BodyType<ReportStatusUpdate>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof updateReportStatus>>,
        TError,
        {id: number;data: BodyType<ReportStatusUpdate>},
        TContext
      > => {
      return useMutation(getUpdateReportStatusMutationOptions(options));
    }

export const getAdminListSubscribersUrl = (params?: AdminListSubscribersParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/admin/newsletter?${stringifiedParams}` : `/api/admin/newsletter`
}

/**
 * @summary Admin list newsletter subscribers
 */
export const adminListSubscribers = async (params?: AdminListSubscribersParams, options?: RequestInit): Promise<PaginatedSubscribers> => {

  return customFetch<PaginatedSubscribers>(getAdminListSubscribersUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





export const getAdminListSubscribersQueryKey = (params?: AdminListSubscribersParams,) => {
    return [
    `/api/admin/newsletter`, ...(params ? [params] : [])
    ] as const;
    }


export const getAdminListSubscribersQueryOptions = <TData = Awaited<ReturnType<typeof adminListSubscribers>>, TError = ErrorType<unknown>>(params?: AdminListSubscribersParams, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof adminListSubscribers>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getAdminListSubscribersQueryKey(params);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof adminListSubscribers>>> = ({ signal }) => adminListSubscribers(params, { signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof adminListSubscribers>>, TError, TData> & { queryKey: QueryKey }
}

export type AdminListSubscribersQueryResult = NonNullable<Awaited<ReturnType<typeof adminListSubscribers>>>
